"use client";

import { memo, useId, useMemo } from "react";
import { cn } from "@/lib/utils";
import {
  DEFAULT_SCHEDULE_LIST_LABELS,
  type ScheduleList01Labels,
  type ScheduleList01Props,
} from "./types";
import { ScheduleRow } from "./parts/schedule-row";

function ScheduleList01Inner({
  items,
  heading,
  headingAs = "h2",
  framed = true,
  linkComponent = "a",
  labels: labelsProp,
  renderItem,
  renderTime,
  emptyState,
  className,
  headingClassName,
  itemClassName,
}: ScheduleList01Props) {
  const headingId = useId();
  const HeadingTag = headingAs;

  const labels = useMemo<Required<ScheduleList01Labels>>(
    () => ({ ...DEFAULT_SCHEDULE_LIST_LABELS, ...labelsProp }),
    [labelsProp],
  );

  const isEmpty = items.length === 0;

  return (
    <section
      aria-labelledby={heading ? headingId : undefined}
      className={cn("space-y-6", className)}
    >
      {heading && (
        <HeadingTag
          id={headingId}
          className={cn(
            "text-2xl font-bold text-foreground",
            headingClassName,
          )}
        >
          {heading}
        </HeadingTag>
      )}

      {isEmpty ? (
        emptyState ?? (
          <p
            role="status"
            className="text-sm text-muted-foreground py-4"
          >
            {labels.emptyText}
          </p>
        )
      ) : (
        <ol
          role="list"
          className={cn(framed ? "space-y-4" : "space-y-2")}
        >
          {items.map((item) =>
            renderItem ? (
              <li key={item.id}>{renderItem(item)}</li>
            ) : (
              <ScheduleRow
                key={item.id}
                item={item}
                framed={framed}
                timeSeparator={labels.timeRangeSeparator}
                renderTime={renderTime}
                linkComponent={linkComponent}
                itemClassName={itemClassName}
              />
            ),
          )}
        </ol>
      )}
    </section>
  );
}

const ScheduleList01 = memo(ScheduleList01Inner);
ScheduleList01.displayName = "ScheduleList01";

export { ScheduleList01 };
export default ScheduleList01;

export { ScheduleList01, default } from "./schedule-list-01";

export type {
  ScheduleListItem,
  ScheduleList01Labels,
  ScheduleList01Props,
} from "./types";

export { DEFAULT_SCHEDULE_LIST_LABELS } from "./types";

export { meta } from "./meta";

import type { ComponentType, ElementType, ReactNode } from "react";

export interface ScheduleListItem {
  /** Stable identifier. Used for React keys + accessible-name composition. */
  id: string;
  /** Time string ("09:00", "14:30", "9pm"). Required — schedules ARE time-anchored. */
  time: string;
  /** Optional end time for a time range. Renders as `${time}{separator}${endTime}` (e.g. "09:00 - 10:30"). */
  endTime?: string;
  /** Item title (bold). Required. */
  title: string;
  /** Item description (muted, smaller). Optional. */
  description?: string;
  /** Optional Lucide-style icon shown left of the time column (e.g. Coffee, Users for break / networking). */
  icon?: ComponentType<{
    className?: string;
    "aria-hidden"?: boolean | "true" | "false";
  }>;
  /** Optional URL — when supplied + `linkComponent` provided, item becomes clickable. */
  href?: string;
}

export interface ScheduleList01Labels {
  /** Default: " - " (with surrounding spaces) — separator between time + endTime. */
  timeRangeSeparator?: string;
  /** Default: "No items scheduled." Used when `items` is empty AND `emptyState` not provided. */
  emptyText?: string;
}

export interface ScheduleList01Props {
  /** Schedule items in display order (chronological). */
  items: ScheduleListItem[];

  /** Optional section heading text. Omit to render without heading (consumer wraps externally). */
  heading?: string;
  /** Heading semantic level. Default: 'h2'. */
  headingAs?: "h2" | "h3" | "h4";

  /** Render per-row card chrome (`bg-card rounded-xl border ...`). Default: true. */
  framed?: boolean;

  /** Element used for clickable items. Default: 'a'. Pass NextLink / RemixLink / etc. */
  linkComponent?: ElementType;

  /** Localized labels. Defaults are English. */
  labels?: ScheduleList01Labels;

  /** Custom per-item renderer — receives the item, returns the row content (replaces the default time + title + description layout). */
  renderItem?: (item: ScheduleListItem) => ReactNode;

  /** Custom time-string renderer — returns ReactNode (e.g. "09:00" → "9:00 AM"). Default: time + optional endTime joined by separator. */
  renderTime?: (item: ScheduleListItem) => ReactNode;

  /** Empty-state slot. Wins over `labels.emptyText` when provided. */
  emptyState?: ReactNode;

  /** Override classes for the root <section>. */
  className?: string;
  /** Override classes for the heading. */
  headingClassName?: string;
  /** Override classes per row. */
  itemClassName?: string;
}

/** Default English labels — exported for consumer composition. */
export const DEFAULT_SCHEDULE_LIST_LABELS: Required<ScheduleList01Labels> = {
  timeRangeSeparator: " - ",
  emptyText: "No items scheduled.",
};

"use client";

import type { ElementType, ReactNode } from "react";
import { cn } from "@/lib/utils";
import type { ScheduleListItem } from "../types";

interface ScheduleRowProps {
  item: ScheduleListItem;
  framed: boolean;
  timeSeparator: string;
  renderTime?: (item: ScheduleListItem) => ReactNode;
  linkComponent: ElementType;
  itemClassName?: string;
}

export function ScheduleRow({
  item,
  framed,
  timeSeparator,
  renderTime,
  linkComponent: LinkComponent,
  itemClassName,
}: ScheduleRowProps) {
  const IconComponent = item.icon;
  const isLinked = item.href != null && item.href.length > 0;

  const timeContent = renderTime ? (
    renderTime(item)
  ) : (
    <span className="text-lg font-bold text-primary">
      {item.time}
      {item.endTime ? `${timeSeparator}${item.endTime}` : null}
    </span>
  );

  return (
    <li
      className={cn(
        "relative group flex items-start gap-4",
        framed &&
          "p-4 bg-card rounded-xl border border-border/50 motion-safe:hover:border-border transition-colors",
        itemClassName,
      )}
    >
      {IconComponent && (
        <div className="shrink-0 mt-1">
          <IconComponent
            aria-hidden="true"
            className="w-5 h-5 text-primary"
          />
        </div>
      )}

      <div className="w-20 shrink-0">{timeContent}</div>

      <div className="min-w-0 flex-1">
        <h4 className="font-semibold text-foreground motion-safe:group-hover:text-primary transition-colors">
          {item.title}
        </h4>
        {item.description && (
          <p className="text-sm text-muted-foreground mt-0.5">
            {item.description}
          </p>
        )}
      </div>

      {isLinked && (
        <LinkComponent
          href={item.href}
          aria-label={item.title}
          className={cn(
            "absolute inset-0 z-0 outline-none",
            framed
              ? "rounded-xl focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-offset-2"
              : "focus-visible:ring-2 focus-visible:ring-ring focus-visible:ring-inset",
          )}
        />
      )}
    </li>
  );
}
